import React from 'react';

const MotorcycleImage = ({ 
  bikeModel, 
  alt, 
  className = '', 
  width = 300, 
  height = 200 
}) => {
  // Map bike models to realistic motorcycle images using placeholder services
  const getImageUrl = (model) => {
    // Using a motorcycle-specific placeholder service or fallback to styled placeholders
    const imageMap = {
      'honda-cb-shine': `https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=${width}&h=${height}&fit=crop&auto=format`,
      'hero-splendor': `https://images.unsplash.com/photo-1558618047-3c8c76ca7d13?w=${width}&h=${height}&fit=crop&auto=format`,
      'bajaj-pulsar-150': `https://images.unsplash.com/photo-1568772585407-9361f9bf3a87?w=${width}&h=${height}&fit=crop&auto=format`,
      'tvs-apache': `https://images.unsplash.com/photo-1609630875171-b1321377ee65?w=${width}&h=${height}&fit=crop&auto=format`,
      'yamaha-fz': `https://images.unsplash.com/photo-1558618047-3c8c76ca7d13?w=${width}&h=${height}&fit=crop&auto=format`,
      're-classic': `https://images.unsplash.com/photo-1609630875171-b1321377ee65?w=${width}&h=${height}&fit=crop&auto=format`,
      'ktm-duke': `https://images.unsplash.com/photo-1568772585407-9361f9bf3a87?w=${width}&h=${height}&fit=crop&auto=format`,
      'suzuki-gixxer': `https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=${width}&h=${height}&fit=crop&auto=format`,
      'honda-activa': `https://images.unsplash.com/photo-1609630875171-b1321377ee65?w=${width}&h=${height}&fit=crop&auto=format`,
      'tvs-jupiter': `https://images.unsplash.com/photo-1558618047-3c8c76ca7d13?w=${width}&h=${height}&fit=crop&auto=format`,
      'bajaj-avenger': `https://images.unsplash.com/photo-1568772585407-9361f9bf3a87?w=${width}&h=${height}&fit=crop&auto=format`,
      'yamaha-r15': `https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=${width}&h=${height}&fit=crop&auto=format`,
      'default': `https://images.unsplash.com/photo-1558618047-3c8c76ca7d13?w=${width}&h=${height}&fit=crop&auto=format`
    };

    return imageMap[model] || imageMap['default'];
  };

  const getBikeDisplayName = (model) => {
    const nameMap = {
      'honda-cb-shine': 'Honda CB Shine',
      'hero-splendor': 'Hero Splendor Plus',
      'bajaj-pulsar-150': 'Bajaj Pulsar 150',
      'tvs-apache': 'TVS Apache RTR 160',
      'yamaha-fz': 'Yamaha FZ-S',
      're-classic': 'Royal Enfield Classic 350',
      'ktm-duke': 'KTM Duke 200',
      'suzuki-gixxer': 'Suzuki Gixxer',
      'honda-activa': 'Honda Activa',
      'tvs-jupiter': 'TVS Jupiter',
      'bajaj-avenger': 'Bajaj Avenger',
      'yamaha-r15': 'Yamaha R15',
      'default': 'Motorcycle'
    };

    return nameMap[model] || nameMap['default'];
  };

  return (
    <div className={`motorcycle-image ${className}`}>
      <img
        src={getImageUrl(bikeModel)}
        alt={alt || getBikeDisplayName(bikeModel)}
        loading="lazy"
        style={{
          width: '100%',
          height: '100%',
          objectFit: 'cover',
          borderRadius: 'var(--radius-md)'
        }}
        onError={(e) => {
          // Fallback to a different placeholder if the image fails to load
          e.target.src = `https://via.placeholder.com/${width}x${height}/2563eb/ffffff?text=${getBikeDisplayName(bikeModel).replace(' ', '+')}`;
        }}
      />
    </div>
  );
};

export default MotorcycleImage;
